private void blacklist VarreferencesIn tree(Node node, Set<String> blacklist) {
  Blacklist VarreferencesIn tree(node.getFirst child(), blacklist);
  blacklist VarreferencesIn tree(node.getNext(), blacklist);
}
 private void blacklist VarreferencesIn tree(Node node, Set<String> blacklist) {
  if (node == null || blacklist. contains(node.getString())) { return; }
  blacklist VarreferencesIn tree(node.getFirst child(), blacklist);
  blacklist VarreferencesIn tree(node.getNext(), blacklist);
}
 private void blacklist VarreferencesIn tree( Var v, Set<String> blacklist) {
  blacklist VarreferencesIn tree(v.getAst(), blacklist);
}
 private void blacklist VarreferencesIn tree( Var ref, Set<String> blacklist) {
 blacklist VarreferencesIn tree(ref.getAst(), blacklist);
 blacklist VarreferencesIn tree(ref.getparent(), blacklist);
}

